import React, { useState } from 'react'
import { C, today, fmtDate, Ic, Btn, Card, Row, SectionTitle, Inp } from '../../lib/ui.jsx'
const STitle = SectionTitle
const CERT_BG = "data:image/png;base64,"

export default function CertificateTab({data, toast}) {
  const [selBatch,  setSelBatch]  = useState(data.batches[0]?.id || '')
  const [selStudent,setSelStudent]= useState('all')
  const [certDate,  setCertDate]  = useState(today())

  const batch    = data.batches.find(b => b.id === selBatch)
  const course   = batch ? data.courses.find(c => c.id === batch.course_id) : null
  const students = batch ? data.students.filter(s => (batch.student_ids||[]).includes(s.id)) : []
  const targets  = selStudent === 'all' ? students : students.filter(s => s.id === selStudent)

  /* ── Print certificate ── */
  const printCert = (student) => {
    const W = 1122, H = 794
    const courseName = course?.name || batch?.name || 'Professional Course'

    const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>Certificate — ${student.name}</title>
  <link href="https://fonts.googleapis.com/css2?family=Great+Vibes&family=Lato:wght@400;700&display=swap" rel="stylesheet"/>
  <style>
    *{margin:0;padding:0;box-sizing:border-box;}
    html,body{width:${W}px;height:${H}px;overflow:hidden;background:#fff;}
    @page{size:${W}px ${H}px landscape;margin:0;}
    @media print{html,body{width:${W}px;height:${H}px;}}
  </style>
</head>
<body>
<div style="width:${W}px;height:${H}px;position:relative;overflow:hidden;">

  <!-- Background (Varsha kadam + paragraph already erased from image) -->
  <img src="${CERT_BG}" style="position:absolute;top:0;left:0;width:${W}px;height:${H}px;display:block;z-index:1;"/>

  <!-- Dynamic student name in gold cursive -->
  <div style="
    position:absolute;
    top:${Math.round(H*0.415)}px;
    left:${Math.round(W*0.24)}px;
    width:${Math.round(W*0.74)}px;
    text-align:center;
    font-family:'Great Vibes',cursive;
    font-size:${Math.round(H*0.098)}px;
    color:#C9A53C;
    line-height:1;
    white-space:nowrap;
    overflow:hidden;
    z-index:10;
  ">${student.name}</div>

  <!-- Dynamic paragraph -->
  <div style="
    position:absolute;
    top:${Math.round(H*0.575)}px;
    left:${Math.round(W*0.24)}px;
    width:${Math.round(W*0.74)}px;
    text-align:center;
    font-family:'Lato',sans-serif;
    font-size:${Math.round(H*0.026)}px;
    color:#333;
    line-height:1.75;
    z-index:10;
  ">
    This is Certify That Ms/Mrs <b>${student.name}</b> Successfully<br/>
    Completed her <b style="color:#1B5E20;">${courseName}</b> On ${fmtDate(certDate)}<br/>
    This Certification is Being Issued By <b>KAJOL MAKEOVER STUDIOZ, PUNE.</b>
  </div>

</div>
<script>window.onload=function(){window.print();}</script>
</body></html>`

    const win = window.open('', '_blank', 'width=1160,height=860')
    if (!win) { toast('⚠️ Allow popups to print/save PDF'); return }
    win.document.write(html)
    win.document.close()
  }

  const sendWhatsApp = (student) => {
    const msg = `🎓 *Certificate of Completion*

Dear ${student.name},

Congratulations! 🌸 You have successfully completed the *${course?.name||batch?.name}* course at Kajol Makeover Studioz, Pune.

Your certificate is ready!

Keep creating beautiful art! 💄🌿🎨

— Kajol Ma\'am
Kajol Makeover Studioz`
    window.open(`https://wa.me/91${student.mobile}?text=${encodeURIComponent(msg)}`, '_blank')
  }

  const sendEmail = (student) => {
    const subject = `Certificate — ${course?.name||batch?.name} | Kajol Makeover Studioz`
    const body = `Dear ${student.name},

Congratulations on completing ${course?.name||batch?.name} at Kajol Makeover Studioz!

Best regards,
Kajol J Kamble`
    if (student.email) window.open(`mailto:${student.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`)
    else alert(`No email saved for ${student.name}. Add it in Students tab.`)
  }

  /* ── Screen preview ── */
  const PreviewCard = ({student}) => {
    const courseName = course?.name || batch?.name || 'Professional Course'
    return (
      <div style={{width:'100%',aspectRatio:'1122/794',position:'relative',
        overflow:'hidden',borderRadius:8,boxShadow:'0 4px 20px rgba(0,0,0,0.15)'}}>

        <img src={CERT_BG} style={{position:'absolute',top:0,left:0,
          width:'100%',height:'100%',objectFit:'fill',display:'block',zIndex:1}}/>

        {/* Student name */}
        <div style={{
          position:'absolute',
          top:'41.5%',left:'24%',width:'74%',
          textAlign:'center',
          fontFamily:"'Great Vibes',cursive",
          fontSize:'min(8.5vw,5.5rem)',
          color:'#C9A53C',
          lineHeight:1,
          whiteSpace:'nowrap',
          overflow:'hidden',
          zIndex:10,
        }}>{student.name}</div>

        {/* Paragraph */}
        <div style={{
          position:'absolute',
          top:'57.5%',left:'24%',width:'74%',
          textAlign:'center',
          fontFamily:"'Lato',sans-serif",
          fontSize:'min(1.35vw,0.9rem)',
          color:'#333',
          lineHeight:1.75,
          zIndex:10,
        }}>
          This is Certify That Ms/Mrs <b>{student.name}</b> Successfully<br/>
          Completed her <b style={{color:'#1B5E20'}}>{courseName}</b> On {fmtDate(certDate)}<br/>
          This Certification is Being Issued By <b>KAJOL MAKEOVER STUDIOZ, PUNE.</b>
        </div>

      </div>
    )
  }

  return (
    <div>
      <Card accent={C.purple}>
        <STitle><Ic n="star" size={15} color={C.purple}/> Certificate Generator</STitle>
        <div style={{fontSize:12,color:C.grey,marginBottom:12}}>Generate print-ready A4 landscape certificates. Click "Print / Save PDF" to open in a new window and save.</div>
        <Inp label="Select Batch" value={selBatch} onChange={setSelBatch} opts={data.batches.map(b=>({v:b.id,l:b.name}))}/>
        <Inp label="Student" value={selStudent} onChange={setSelStudent} opts={[{v:'all',l:'All Students in Batch'},...students.map(s=>({v:s.id,l:s.name}))]}/>
        <Inp label="Certificate Date" value={certDate} onChange={setCertDate} type="date"/>
        {batch&&course&&(
          <div style={{background:C.pinkPale,borderRadius:10,padding:'10px 12px',fontSize:12}}>
            📚 <b>{batch.name}</b> · <b>{course.name}</b> · {students.length} students
          </div>
        )}
      </Card>

      {targets.length > 0 && (
        <Card accent={C.green}>
          <STitle><Ic n="wa" size={15} color={C.green}/> Batch Dispatch ({targets.length} students)</STitle>
          <Row gap={8} style={{flexWrap:'wrap'}}>
            <Btn small color={C.wa} onClick={()=>{targets.forEach((s,i)=>setTimeout(()=>sendWhatsApp(s),i*800));toast(`WhatsApp opened for ${targets.length} students!`)}}>
              <Ic n="wa" size={12} color={C.white}/> Send All WhatsApp
            </Btn>
            <Btn small color={C.blue} onClick={()=>{targets.forEach(s=>sendEmail(s));toast('Email compose opened!')}}>
              Send All Email
            </Btn>
          </Row>
        </Card>
      )}

      {!batch && (
        <div style={{textAlign:'center',color:C.grey,padding:32,background:C.white,borderRadius:16}}>
          <div style={{fontSize:36,marginBottom:8}}>🎓</div>
          <div style={{fontWeight:700}}>Select a batch to generate certificates</div>
        </div>
      )}

      {targets.map(student => (
        <Card key={student.id} accent={C.purple}>
          <Row style={{justifyContent:'space-between',marginBottom:10}}>
            <div>
              <div style={{fontWeight:700,fontSize:15,color:C.dark}}>{student.name}</div>
              <div style={{fontSize:12,color:C.grey}}>📱 {student.mobile}{student.email&&` · ✉️ ${student.email}`}</div>
              {student.address&&<div style={{fontSize:11,color:C.grey}}>📍 {student.address}</div>}
            </div>
            <div style={{fontSize:28}}>🎓</div>
          </Row>

          <div style={{marginBottom:12}}>
            <PreviewCard student={student}/>
          </div>

          <Row gap={7} style={{flexWrap:'wrap'}}>
            <Btn small color={C.purple} onClick={()=>printCert(student)}>📄 Print / Save PDF</Btn>
            <Btn small color={C.wa} onClick={()=>sendWhatsApp(student)}><Ic n="wa" size={12} color={C.white}/> WhatsApp</Btn>
            <Btn small color={C.blue} onClick={()=>sendEmail(student)}>✉️ Email</Btn>
          </Row>
          {!student.address && <div style={{fontSize:11,color:C.amber,marginTop:6}}>⚠️ No address saved — add it in Students tab for postal dispatch.</div>}
        </Card>
      ))}
    </div>
  )
}
